/* ═══════════════════════════════════════════════════
   UGIP — notice.js  (page-specific interactions)
═══════════════════════════════════════════════════ */
fetch('https://gpnainital.com/api/data/notices?key=8b484ef3cbc00cb09e9f46e92bf359bb896b64d9d50ce6f71a2226efc67db722')
  .then(res => res.json())
  .then(data => {
    // data.data contains the database records!
    console.log(data.data);

    // Example: Render inside your component
    const container = document.getElementById('my-grid');
    data.data.forEach(row => {
      container.innerHTML += 
        <div class="card">
           <h3>+row.title+</h3>
        </div>;
    });
  });
(function() {
  'use strict';

let currentCat = 'all';
function setCat(cat, btn) {
  currentCat = cat;
  document.querySelectorAll('.filter-tag').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  filterNotices();
}
function filterNotices() {
  const q = document.getElementById('searchInput').value.toLowerCase();
  const cards = document.querySelectorAll('.notice-card');
  let visible = 0;
  cards.forEach(card => {
    const matchCat = currentCat === 'all' || card.dataset.cat === currentCat;
    const matchQ = !q || card.dataset.title.includes(q) || card.innerText.toLowerCase().includes(q);
    card.style.display = (matchCat && matchQ) ? 'block' : 'none';
    if (matchCat && matchQ) visible++;
  });
  document.getElementById('noResults').style.display = visible === 0 ? 'block' : 'none';
}

