/* ── Inline scripts moved from HTML ── */
let currentCat = 'all';
function setCat(cat, btn) {
  currentCat = cat;
  document.querySelectorAll('.filter-tag').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  filterNotices();
}
function filterNotices() {
  const q = document.getElementById('searchInput').value.toLowerCase();
  const cards = document.querySelectorAll('.notice-card');
  let visible = 0;
  cards.forEach(card => {
    const matchCat = currentCat === 'all' || card.dataset.cat === currentCat;
    const matchQ = !q || card.dataset.title.includes(q) || card.innerText.toLowerCase().includes(q);
    card.style.display = (matchCat && matchQ) ? 'block' : 'none';
    if (matchCat && matchQ) visible++;
  });
  document.getElementById('noResults').style.display = visible === 0 ? 'block' : 'none';
}
